// SIN mocking: llama a la API real (lento, poco confiable)
test('muestra el clima', async () => {
  const weather = await fetchWeather('NYC'); // Llamada real a la API!
  expect(weather.temp).toBeDefined();
});

// CON mocking: simula la respuesta de la API (rapido, confiable)
test('muestra el clima', async () => {
  jest.spyOn(api, 'fetchWeather').mockResolvedValue({
    temp: 72, condition: 'soleado'
  });
  const weather = await fetchWeather('NYC'); // Devuelve datos simulados!
  expect(weather.temp).toBe(72);
});
